@layer reset, base, components;

@layer reset {
  * { box-sizing: border-box; }
}

@layer base {
  button { font: inherit; }
}

@layer components {
  .button { background: #123; color: white; }
}

button[aria-pressed="true"] { color: gold; }

.card > h2 + p::first-line {
  font-weight: 700;
}

button:is(:hover, :focus-visible) {
  outline: 2px solid currentColor;
}

[aria-expanded="true"] > .chevron {
  transform: rotate(180deg);
}

:where(nav a) {
  text-decoration: none;
}

@layer tokens, base, components;

@layer tokens {
  :root {
    --surface: #111827;
    --surface-elevated: #1f2937;
    --text: #f9fafb;
  }
}

@layer base {
  body {
    background: var(--surface);
    color: var(--text);
  }
}

@layer components {
  .panel {
    background: var(--surface-elevated);
    color: var(--text);
  }
}

@scope (.panel) {
  button {
    color: inherit;
  }
}

.card {
  box-sizing: border-box;
  width: min(100%, 28rem);
  padding: 1rem;
  border: 1px solid #374151;
  position: relative;
  overflow: clip;
}

.card .badge {
  position: absolute;
  top: 0.75rem;
  right: 0.75rem;
}

.card .sticky-note {
  position: sticky;
  top: 0;
}

.toolbar {
  display: flex;
  align-items: center;
  gap: 1rem;
}

.toolbar__search {
  flex: 1 1 20rem;
  min-width: 0;
}

.toolbar__actions {
  margin-inline-start: auto;
  display: flex;
  gap: 0.5rem;
}

.card-grid {
  display: grid;
  gap: 1.5rem;
  grid-template-columns: repeat(auto-fit, minmax(14rem, 1fr));
}

.card {
  display: grid;
  gap: 0.75rem;
  grid-template-rows: auto auto 1fr;
}

.card__meta {
  grid-column: 1 / -1;
}

.card__detail {
  display: grid;
  grid-template-columns: subgrid;
  grid-column: 1 / -1;
}

.layout {
  padding-block: clamp(1rem, 3vw, 2rem);
  padding-inline: clamp(1rem, 4vw, 2rem);
}

.panel {
  container-type: inline-size;
}

.panel__body {
  display: grid;
  gap: 1rem;
}

@media (width >= 60rem) {
  .layout {
    grid-template-columns: 18rem minmax(0, 1fr);
  }
}

@container (width > 32rem) {
  .panel__body {
    grid-template-columns: 12rem minmax(0, 1fr);
  }
}

.feature-card {
  color: oklch(0.22 0.03 250);
  background: linear-gradient(135deg, oklch(0.98 0.02 250), oklch(0.92 0.03 270));
  border: 1px solid oklch(0.84 0.04 250);
  border-radius: 1.25rem;
  box-shadow: 0 18px 40px oklch(0.2 0.02 250 / 0.12);
  padding: clamp(1.25rem, 3vw, 2rem);
}

.feature-card h3 {
  font-size: clamp(1.25rem, 2vw, 1.75rem);
  line-height: 1.15;
  text-wrap: balance;
}

.feature-card p {
  line-height: 1.6;
  max-width: 60ch;
}

:root {
  --motion-fast: 160ms;
  --motion-normal: 240ms;
  --motion-ease: cubic-bezier(0.2, 0, 0, 1);
}

.card {
  transition: transform var(--motion-fast) var(--motion-ease),
    box-shadow var(--motion-fast) var(--motion-ease);
}

.card:hover {
  transform: translateY(-2px) scale(1.01);
}

@keyframes pulse-ring {
  from {
    transform: scale(0.95);
    opacity: 0.7;
  }
  to {
    transform: scale(1.15);
    opacity: 0;
  }
}

.badge::after {
  animation: pulse-ring 1.2s ease-out infinite;
}

@layer reset, tokens, base, components, utilities;

@layer reset {
  *, *::before, *::after {
    box-sizing: border-box;
  }

  body, h1, h2, p {
    margin: 0;
  }
}

@layer tokens {
  :root {
    --space-2: 0.5rem;
    --space-4: 1rem;
    --radius-2: 0.5rem;
    --color-surface: #0f172a;
  }
}

@layer components {
  .card {
    padding: var(--space-4);
    border-radius: var(--radius-2);
    background: var(--color-surface);
  }
}

.feed-card {
  contain: layout paint;
  content-visibility: auto;
  contain-intrinsic-size: 16rem;
}

.feed-card .thumbnail {
  aspect-ratio: 16 / 9;
  object-fit: cover;
}

.status-chip {
  will-change: transform;
  transform: translateZ(0);
}

.button {
  color: #fff;
  background: #1d4ed8;
  accent-color: #1d4ed8;
  color-scheme: light dark;
}

.button:focus-visible {
  outline: 3px solid currentColor;
  outline-offset: 2px;
}

@media (prefers-reduced-motion: reduce) {
  .button { transition: none; }
}

@media (forced-colors: active) {
  .button { forced-color-adjust: auto; border-color: ButtonText; }
}

.trigger { anchor-name: --trigger; }
.tooltip { position: absolute; position-anchor: --trigger; top: anchor(bottom); }
.menu { popover: auto; }
.field { color-scheme: light dark; accent-color: #0f766e; }

@layer tokens, components, utilities;
:root { --surface: #0f172a; --text: #f8fafc; }
.card { background: var(--surface); color: var(--text); }
.stack-gap-4 { gap: 1rem; }
